Part.Source:
&EmPCod = val(substr(&ParamentroEmpresa, 1, 9))
&TefCod = val(substr(&ParamentroEmpresa, 10, 9))

&TefMsg = &parTefMsg
if &OqueFazer <> 'LINX_SUCESSO' and &OqueFazer <> 'LINX_LOG'	
	&TefMsg = &TefMsg.Replace("%$#", " ")
	&TefMsg = &TefMsg.Replace("+$@", '"')

	&TefMsg = Trim(strreplace(&TefMsg,Chr(10),' '))
	&TefMsg = Trim(strreplace(&TefMsg,Chr(13),' '))
Endif


Do Case
	Case &OqueFazer = 'ID'
		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod		

			TefStsSyncServ = 'N'
			TefID = &TefMsg
			Exit
		EndFor

		Commit
		do 'gravaItemObs'

	Case &OqueFazer = 'IDLINX'
		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod
			&FilCod = TefFilCod
			&PedCod = TefPedCod
			&TefGuid = TefGUID

			TefID = &TefMsg

			Exit
		EndFor

		Commit

		if &PedCod > 0 //TEM PEDIDO	
			GravaDuplicataPedidoTEF.Call('ID', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
		Endif

		do 'gravaItemObs'

	Case &OqueFazer = 'PORTA'
		//ATUALIZAR A PORTA DO TEF

	Case &OqueFazer = '#DESFAZCARTAO#'
		&TEfSts = 'C' //CANCELADO

		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod

			TefSts = &TEfSts //DESFEITO
			TefStsCnf = 'S' //CONFIRMADO

			Exit
		EndFor
		do 'gravaItemObs'

	Case &OqueFazer = 'LINX_LOG'
		for Each Order EmpCod, PdvCod
			Where EmpCod = &EmpCod

			&EmpImpCod = PdvImpCod

			Exit
		EndFor

		do 'getNSULog'

		if &IsExtorno = true
			&TEfSts = 'C'	
		Else
			&TEfSts = 'S'
		Endif

		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod

			&TefGuid = TefGUID
			&TefBanCarCod = TefBanCarCod

			TefSts = &TEfSts//SUCESSO
			TefStsCnf = 'S' //CONFIRMADO
			TefStsSyncServ = 'N'			

			if not &NsuVarchar.IsEmpty() //TefID.IsEmpty() or TefID.IsNull() and
				TefID = &NsuVarchar
			Endif
			if not &AutorizacaoVarchar.IsEmpty()
				TefIdAut = &AutorizacaoVarchar
			Endif		
			if not &TefBandCod.IsEmpty() //TefBandCod.IsEmpty() or TefBandCod.IsNull() and 
				TefBandCod = &TefBandCod
			Endif
			if not &TefBand.IsEmpty() //and (TefBand.IsEmpty()  or TefBand.IsNull())
				TefBand =  &TefBand.ToUpper()
			Endif
			if not &TefBandCnpj.IsEmpty() //and (TefBandCnpj.IsEmpty()  or TefBandCnpj.IsNull())
				TefBandCnpj =  &TefBandCnpj.ToUpper()
			Endif
			if not &TefCardNom.IsEmpty() //and (TefCardNom.IsEmpty()  or TefCardNom.IsNull())
				TefCardNom =  &TefCardNom.ToUpper()
			Endif

			&FilCod = TefFilCod
			&PedCod = TefPedCod

			//&PedVencod = PedVenCod

			if TefCreDebVou <> 'C' //DEBITO
				&PedItmFrpPgtoCod = 5 //TipoFormaPagamentoPDV.CARTAO_D
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(1)
			Else //CREDITO
				&PedItmFrpPgtoCod = 8 //TipoFormaPagamentoPDV.CARTAO_C
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(30)
			EndIf

			&TefVlr = TefVlr
			Exit
		EndFor
		Commit

		//versao 2.5 do PDV nao vai ser impressao via webservice, vai ser impressao via pdv

		if &PedCod > 0 //TEM PEDIDO	
			if &TEfSts = 'C' //CANCELADO
				GravaDuplicataPedidoTEF.Call('DEL', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
			Else
				GravaDuplicataPedidoTEF.Call('ADD', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
			Endif
		Endif

		&TEfSts = 'L' //REGISTRO DE LOG
		do 'gravaItemObs'

	Case &OqueFazer = 'LINX_SUCESSO' or &OqueFazer = 'LINX_CANCELA'	
		for Each Order EmpCod, PdvCod
			Where EmpCod = &EmpCod

			&EmpImpCod = PdvImpCod

			Exit
		EndFor

		&XmlIMprimirLongVarchar = &TefMsg.Trim()

		if &TefMsg <> 'LINX_SUCESSO'	
			do 'getNSU'
		Endif

		if &OqueFazer = 'LINX_CANCELA'	
			&TEfSts = 'C'	
		Else
			&TEfSts = 'S'
		Endif

		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod

			&TefGuid = TefGUID
			&TefBanCarCod = TefBanCarCod

			TefSts = &TEfSts//SUCESSO
			TefStsSyncServ = 'N'

			if (TefID.IsEmpty() or TefID.IsNull()) and not &NsuVarchar.IsEmpty()
				TefID = &NsuVarchar
			Endif

			&FilCod = TefFilCod
			&PedCod = TefPedCod

			//&PedVencod = PedVenCod

			if TefCreDebVou <> 'C' //DEBITO
				&PedItmFrpPgtoCod = 5 //TipoFormaPagamentoPDV.CARTAO_D
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(1)
			Else //CREDITO
				&PedItmFrpPgtoCod = 8 //TipoFormaPagamentoPDV.CARTAO_C
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(30)
			EndIf

			&TefVlr = TefVlr
			Exit
		EndFor
		Commit

		//versao 2.5 do PDV nao vai ser impressao via webservice, vai ser impressao via pdv

		if &PedCod > 0 //TEM PEDIDO	
			if &TEfSts = 'C' //CANCELADO
				GravaDuplicataPedidoTEF.Call('DEL', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
			Else
				GravaDuplicataPedidoTEF.Call('ADD', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
			Endif
		Endif

		do 'gravaItemObs'

	Case &OqueFazer = 'CAPPTA_APROVADA'
		for Each Order EmpCod, PdvCod
			Where EmpCod = &EmpCod

			&EmpImpCod = PdvImpCod

			Exit
		EndFor

		&XmlIMprimirLongVarchar = &TefMsg.Trim()

		&sdtCappta.FromJson(&XmlIMprimirLongVarchar)		

		&TEfSts = 'S'
		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod

			&TefGuid = TefGUID
			&TefBanCarCod = TefBanCarCod

			TefSts = &TEfSts//SUCESSO
			TefStsCnf = 'S' //SUCESSO
			TefStsSyncServ = 'N'

			if not &sdtCappta.NomeBandeiraCartao.IsEmpty()
				TefBand =  upper(&sdtCappta.NomeBandeiraCartao)
			Endif

			&FilCod = TefFilCod
			&PedCod = TefPedCod

			//&PedVencod = PedVenCod
			&AutorizacaoVarchar = &sdtCappta.CodigoAutorizacaoAdquirente
			&NsuVarchar = &sdtCappta.NSUAdquirente

			if TefCreDebVou = 'D' //DEBITO
				&PedItmFrpPgtoCod = 5 //TipoFormaPagamentoPDV.CARTAO_D
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(1)
			Else //CREDITO
				&PedItmFrpPgtoCod = 8 //TipoFormaPagamentoPDV.CARTAO_C
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(30)
			EndIf

			&TefVlr = TefVlr
			Exit
		EndFor
		Commit

		//versao 2.5 do PDV nao vai ser impressao via webservice, vai ser impressao via pdv

		if &PedCod > 0 //TEM PEDIDO			
			Call(GravaDuplicataPedidoTEF, 'ADD', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
		Endif

		do 'gravaItemObs'

	Case &OqueFazer = 'SUCESSO'
		for Each Order EmpCod, PdvCod
			Where EmpCod = &EmpCod

			&EmpImpCod = PdvImpCod

			Exit
		EndFor

		&XmlIMprimirLongVarchar = &TefMsg.Replace('metadata:{},', '')
		&XmlIMprimirLongVarchar = &TefMsg.Replace('"metadata":{},', '')
		&sdtComprovante.FromJson(&XmlIMprimirLongVarchar)

		&TEfSts = 'S'
		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod

			&TefGuid = TefGUID
			&TefBanCarCod = TefBanCarCod

			TefSts = &TEfSts//SUCESSO
			TefStsCnf = 'S' //SUCESSO
			TefStsSyncServ = 'N'

			if not  &sdtComprovante.payment_method.card_brand.IsEmpty()
				TefBand =  upper(&sdtComprovante.payment_method.card_brand)
			Endif

			&FilCod = TefFilCod
			&PedCod = TefPedCod

			//&PedVencod = PedVenCod
			&AutorizacaoVarchar = &sdtComprovante.payment_authorization.authorization_code

			&NsuVarchar = &sdtComprovante.payment_authorization.authorization_nsu

			if TefCreDebVou = 'D' //DEBITO
				&PedItmFrpPgtoCod = 5 //TipoFormaPagamentoPDV.CARTAO_D
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(1)
			Else //CREDITO
				&PedItmFrpPgtoCod = 8 //TipoFormaPagamentoPDV.CARTAO_C
				&PedFrpDtaVct = serverDate()
				&PedFrpDtaVct = &PedFrpDtaVct.AddDays(30)
			EndIf

			&TefVlr = TefVlr
			Exit
		EndFor
		Commit

		//versao 2.5 do PDV nao vai ser impressao via webservice, vai ser impressao via pdv
		//prcGravaImpressao.Call(&EmpCod, &EmpImpCod, 'TEF_COMPROVANTE_C', &FilCod, &PedCod, &PedVencod, &TefMsg, 0, serverDate())
		if &PedCod > 0 //TEM PEDIDO			
			Call(GravaDuplicataPedidoTEF, 'ADD', &EmpCod, &FilCod, &PedCod, &PedItmFrpPgtoCod, &TefVlr, 0, &PedFrpDtaVct, &AutorizacaoVarchar, &NsuVarchar, &TefCod, &TefGuid, &TEfBancArCod, &TefCardNom)
		Endif		

		do 'gravaItemObs'

	Case &OqueFazer = 'FALHA' or &OqueFazer = 'CAPPTA_ERRO' or &OqueFazer = 'LINX_ERRO'	
		&TEfSts = 'F'
		For Each Order EmpCod, TefCod
			Where EmpCod = &EmPCod
			Where TefCod = &TefCod
			TefStsSyncServ = 'N'

			if TefSts <> 'S' and TefSts <> 'C'
				TefSts = &TEfSts //FALHA
				TefStsCnf = 'S' //SUCESSO
			Endif

			Exit
		EndFor
		Commit
		do 'gravaItemObs'

	Case &OqueFazer = 'MENSAGEM' or &OqueFazer = 'CAPPTA_MENSAGEM'	 or &OqueFazer = 'LINX_MSG'	 or &OqueFazer = 'LINX_LOG'	
		do 'gravaItemObs'

	Otherwise
		do 'gravaItemObs'
EndCase

Sub 'getNSULog'
	&NsuVarchar.SetEmpty()
	&AutorizacaoVarchar.SetEmpty()
	&TefBand.SetEmpty()
	&TefBandCod.SetEmpty()
	&TefCardNom.SetEmpty()
	&TefBandCnpj.SetEmpty()

	&auxTefMsg = &TefMsg
	&TipoRegistro = Substr(&auxTefMsg, 11, 3)
	&IsExtorno = false

	&Texto = &auxTefMsg.Substring(1, 255)
	&auxTefMsg = &auxTefMsg.Replace(&Texto, '')
	Do Case
		//CAse not &auxTefMsg.IsEmpty() and &TipoRegistro = 'QRC' //QR CODE

		CAse not &auxTefMsg.IsEmpty() and (&TipoRegistro = 'CCR' or &TipoRegistro = 'CDB' or &TipoRegistro = 'CCV') //CARTAO CREDITO, DEBITO, VOUCHER
			//0001000301CCR2409202417090801004        000000000000000226606485464******8224*********************1127AV00S         00000000000000000000000000000000000000123458001059123458                    0000000000000000000000000000000000000000000000000000000023300010001000301CCR2409202417090801004001059000000000226000000000000000000000226000100010000123458         01000001250000000101027058000191123458                          0001PAYWAVE/VISA
			//NumeroEmpresa	4 N	
			//NumeroLoja	6 N	
			//TipoRegistro	3 A	 [CCR] Cartão de Crédito	
			//Data	8 N	
			//Hora	6 N	
			//CodigoTransacao	2 N	Codigo da transação solicitada
			//NumeroEquipamento	3 N	
			//NumeroFiscalEquipamento	8 N	Número de registro junto à Receita Federal
			//NumeroCupom	6 N	Número do cupom (fiscal ou não fiscal)
			//ValorTransacao	12 N	10 inteiros, 2 decimais

			Do CASe
				CAse &TipoRegistro = 'CCV'
					//Reservado	1 A	
					//NumeroAutorizador	2 N	Veja Tabela 2.0 de Redes Autorizadoras
					&numeroCartao = &Texto.Substring(68,10)//NumeroCartao	37 A	Conteúdo da trilha 2 sem bytes sentinelas
					//VencimentoCartao	4 N	Formato MMAA
					//CodigoResposta	2 N	
					//NumeroControleRede	9 A	NSU Rede (número seqüencial único)
					&NsuVarchar = &Texto.Substring(114, 6) //NumeroControle	6 N	NSU (número seqüencial único)
					&AutorizacaoVarchar = &Texto.Substring(120, 6) //NumeroAutorizacaoRede	6 A	
					//MensagemErro	20 A	
					//Reservado	55 A	
					//CodigoOperadora	4 N	Veja Tabela 4.0 de Operadoras
					//NumeroAutorizador8	4 N	Rede Autorizadora do Linx TEF

				Case &TipoRegistro = 'CDB'
					//CartaoPrePago	1 A
					//NumeroAutorizador	2 N	
					&numeroCartao = &Texto.Substring(68,10)//NumeroCartao	37 A	Conteúdo da trilha 2 sem bytes sentinelas
					//VencimentoCartao	4 N	Formato MMAA
					//TipoOperacao	2 A	 [PS] Parcelada (sem juros) [PC] Parcelada (com juros) [PD] Pré-datada
					//NumeroParcelas	2 N	Número de parcelas da transação
					//SequenciaParcela	2 N	Seqüência da parcela na transação
					//DataDebito	8 N	Data da parcela (transação parcelada) ou Data de débito (transação pré-datada)
					//ValorParcela	12 N	10 inteiros, 2 decimais
					//ValorTaxaServico	12 N	10 inteiros, 2 decimais
					//TipoTransacao	1 N	 [0] Transação Normal [1] Transação Forçada
					//CodigoSupervisor	8 A	Código do Supervisor autorizador da Transação Forçada
					//CodigoResposta	2 N	
					//NumeroControleRede	9 A	NSU Rede (número seqüencial único)
					&NsuVarchar = &Texto.Substring(161, 6) //NumeroControle	6 N	NSU (número seqüencial único)
					&AutorizacaoVarchar = &Texto.Substring(167, 6) //NumeroAutorizacaoRede	6 A	
					//MensagemErro	20 A	
					//TextoGenerico	22 A	CPF, CNPJ, Pontos Adquiridos, Fator de Compra, etc
					//ValorSaque	12 N	10 inteiros, 2 decimais
					//ValorTaxaEmbarque	12 N	10 inteiros, 2 decimais
					//Reservado 3	9 A	
					//CodigoOperadora	4 N	Veja Tabela 4.0 de Operadoras
					//NumeroAutorizador8	4 N	Rede Autorizadora do Linx TEF

				CAse &TipoRegistro = 'CCR'
					//TipoColetaCartao	1 N [0] Tarja magnética [1] Digitado [2] Chip TIBC 1 [3] Chip TIBC 3 [4] Chip com contato EMV [5] Sem contato tarja [6] Sem contato EMV
					//NumeroAutorizador	2 N	Veja Tabela 2.0 de Redes Autorizadoras
					&numeroCartao = &Texto.Substring(68,10)//NumeroCartao	37 A	Conteúdo da trilha 2 sem bytes sentinelas
					//VencimentoCartao	4 N	Formato MMAA
					//TipoOperacao	2 A	//[AV] À Vista [FL] Financiamento Lojista (sem juros) [FA] Financiamento Administradora (com juros)
					//NumeroParcelas	2 N	Número de parcelas da transação
					//CartaoPrePago	1 A	Indicativo se é um cartão pré-pago, respostas possiveis: 'S' (Sim), 'N' (Não) ou ' ' (para redes que não informam o tipo do cartão)
					//Reservado	9 A	
					//ValorParcela	12 N	10 inteiros, 2 decimais
					//ValorTaxaServico	12 N	10 inteiros, 2 decimais
					//Reservado	9 A	
					//CodigoResposta	2 N	
					//NumeroControleRede	9 A	NSU Rede (número seqüencial único)
					&NsuVarchar = &Texto.Substring(161, 6)//NumeroControle	6 N	NSU (número seqüencial único)
					&AutorizacaoVarchar = &Texto.Substring(167,6) //NumeroAutorizacaoRede	6 A	
					//MensagemErro	20 A	
					//ValorTaxaEmbarque	12 N	10 inteiros, 2 decimais
					//CPF ou CNPJ	14 A	CPF ou CNPJ retornado na transação
					//Reservado	29 A	
					//CodigoOperadora	4 N	Veja Tabela 4.0 de Operadoras
					//NumeroAutorizador8	4 N	Rede Autorizadora do Linx TEF
			EndCAse

			&Texto = &auxTefMsg.Trim() //resto do codigo

			//7002 //numero empresa 4N
			//004451 //numero loja 6N
			//CNC //TipoRegistro	3 A
			//18062024 //Data	8 N	
			//200607 //Hora	6 N	
			//07 //CodigoTransacao	2 N	Codigo da transação solicitada
			//002 //NumeroEquipamento	3 N	
			//&NsuVarchar = &Texto.Substring(106, 6) //004715 //NumeroControle	6 N	NSU (número sequencial único)
			//000000000100 //ValorOriginal	12 N	Valor original da transação
			//000000000000 //ValorDesconto	12 N	Valor do desconto
			//000000000100 //ValorFinal	12 N	Valor final da transação (Original – Desconto)
			&auxTefBandCod = val(&Texto.Substring(75, 4)) //0002 //CodigoBandeira	4 N	Código da bandeira do cartão (Tabela 5.0)
			//0000 //CodigoProdutoRede	4 N
			//0000 //CodigoBandeiraRede	4 N
			//ID //002000096      // NumeroControleRede	15 A	
			//01 //CódigoTEFTerceiro	2 N	
			//00000181 //CodigoRedeTerceiro	8 N
			//00000099 //CodigoBandeiraTerceiro	8 N
			&TefBandCnpj = &Texto.Substring(120, 14) //10440482000154 //CNPJRedeAdquirente	14 N
			//002000096                       //NumeroControleRedeAdicional 32 A	NSU Rede para rede Stone
			&TefBandCod = val(&Texto.Substring(166, 4)) //0002 //CodigoBandeiraSefaz	4 N	Código da Bandeira na Sefaz
			&TefCardNom = &Texto.Substring(170,32) ////NomePortador	32 A	Nome do portador do cartão
			////Reservado	54 A	

			//localizaNome Bandeira
			&TefBand = prcRetonaNomeBandeiraSefaz.udp(&auxTefBandCod)

			iF &TefCardNom.IsEmpty()
				&TefCardNom = &numeroCartao
			EndIf

		CAse not &auxTefMsg.IsEmpty() and &TipoRegistro = 'CNC' //CANCELAMENTO
			&IsExtorno = true

			//LOG ADICIONAL
			//7002//NumeroEmpresa	4 N	
			//004451//NumeroLoja	6 N	
			//CNC//TipoRegistro	3 A //CANCELAMENTO
			//18062024//Data	8 N	
			//200607//Hora	6 N	
			//07//CodigoTransacao	2 N
			//002//NumeroEquipamento	3 N	
			//1       //NumeroFiscalEquipamento	8 N
			//000000//NumeroCupom	6 N
			//000000000100//ValorTransacao	12 N
			//6//TipoColetaCartao	1 N	//[0] Tarja magnética [1] Digitado [2] Chip TIBC 1 [3] Chip TIBC 3 [4] Chip com contato EMV [5] Sem contato tarja [6] Sem contato EMV
			//99//NumeroAutorizador	2 N
			//536119******7569*********************//NumeroCartao	37 A
			//0527//VencimentoCartao	4 N	Formato MMAA    
		    //Reservado	4 A	
			//004704//NumeroControleCancelado	6 N	NSU da transação cancelada
            //   //Reservado	37 A	
			//00//CodigoResposta	2 N	
			//002000096//NumeroControleRede	9 A	NSU Rede (número seqüencial único)
			&NsuVarchar = &auxTefMsg.Substring(161,6) //004715//NumeroControle	6 N	NSU (número seqüencial único)
			&AutorizacaoVarchar = &auxTefMsg.Substring(167,6) //R04952//NumeroAutorizacaoRede	6 A                    //MensagemErro	20 A
			//                                                       //Reservado	55 A	
