			//0026//NumeroAutorizador8	4 N	Rede Autorizadora do Linx TEF

			//&adicionaIndex = 255			
			//LOG ESTENDIDO 1 = 256

			//7002 //numero empresa 4N
			//004451 //numero loja 6N
			//CNC //TipoRegistro	3 A
			//18062024 //Data	8 N	
			//200607 //Hora	6 N	
			//07 //CodigoTransacao	2 N	Codigo da transação solicitada
			//002 //NumeroEquipamento	3 N	
			//004715 //NumeroControle	6 N	NSU (número sequencial único)
			//000000000100 //ValorOriginal	12 N	Valor original da transação
			//000000000000 //ValorDesconto	12 N	Valor do desconto
			//000000000100 //ValorFinal	12 N	Valor final da transação (Original – Desconto)
			//0002 //CodigoBandeira	4 N	Código da bandeira do cartão (Tabela 5.0)
			//0000 //CodigoProdutoRede	4 N
			//0000 //CodigoBandeiraRede	4 N
			//002000096      // NumeroControleRede	15 A	
			//01 //CódigoTEFTerceiro	2 N	
			//00000181 //CodigoRedeTerceiro	8 N
			//00000099 //CodigoBandeiraTerceiro	8 N
			//10440482000154 //CNPJRedeAdquirente	14 N
			//002000096                       //NumeroControleRedeAdicional 32 A	NSU Rede para rede Stone
			//&TefBandCod = val(&auxTefMsg, ) 0002 //CodigoBandeiraSefaz	4 N	Código da Bandeira na Sefaz
			////NomePortador	32 A	Nome do portador do cartão
			////Reservado	54 A	
	EndCase
EndSub

sub 'getNSU'
	&NsuVarchar.SetEmpty()
	&AutorizacaoVarchar.SetEmpty()
	&TefBand.SetEmpty()
	&Count = 0
	&IsExtorno = false

		Do CAse
			CAse &XmlIMprimirLongVarchar.ToUpper() like '%GETNET%'

				For &Mensagem in &XmlIMprimirLongVarchar.SplitRegEx(';:;')

					&Mensagem = &Mensagem.ToUpper()

					if not &Mensagem.IsEmpty()
						&Count += 1	
						do case
							Case &Count = 9
								&index = &Mensagem.IndexOf('****', 1)
								&index = &index-1
								&TefBand = &Mensagem.Substring(1,&index)
								&TefBand = &TefBand.Trim()

							CAse &Mensagem like '%NSU%' and &NsuVarchar.IsEmpty()
								&NsuVarchar = &Mensagem
								&NsuVarchar = RetornaSoNumeros.UDP(&NsuVarchar)

							Case &Mensagem like '%AUT:%' and &AutorizacaoVarchar.IsEmpty()
								&index1 = &Mensagem.IndexOf('AUT:', 1)
								&index2 = &Mensagem.IndexOf('DOC:', 1)
								&AutorizacaoVarchar = &Mensagem.Substring(&index1, &index2-&index1)

								&AutorizacaoVarchar = &AutorizacaoVarchar.Replace('AUT:', '')
								&AutorizacaoVarchar = &AutorizacaoVarchar.Replace('DOC:', '')
								&AutorizacaoVarchar = &AutorizacaoVarchar.Trim()

							Case &Mensagem like '%ID:%' and &TefIdAut.IsEmpty()
								&TefIdAut = &Mensagem
								&TefIdAut = &TefIdAut.Replace('AID:', '')
								&TefIdAut = &TefIdAut.Trim()

							Case &Mensagem like '%ESTORNO%'
								&IsExtorno = true
						EndCase
					Endif

					//					if not &NsuVarchar.IsEmpty() and not &AutorizacaoVarchar.IsEmpty()
					//						Exit
					//					Endif

				EndFor

			CAse &XmlIMprimirLongVarchar.ToUpper() like '%STONE%'

				For &Mensagem in &XmlIMprimirLongVarchar.SplitRegEx(';:;')

					&Mensagem = &Mensagem.ToUpper()

					if not &Mensagem.IsEmpty()
						&Count += 1	
						do case
							Case &Count = 6
								&TefBand = &Mensagem
							CAse &Mensagem like '%NSU%'
								&NsuVarchar = RetornaSoNumeros.UDP(&Mensagem)
							Case &Mensagem like '%AUTORIZACAO:%' or &Mensagem like '%AUT:%'
								&AutorizacaoVarchar = RetornaSoNumeros.UDP(&Mensagem)
							Case &Mensagem like '%ID:%' and &TefIdAut.IsEmpty()
								&TefIdAut = &Mensagem
								&TefIdAut = &TefIdAut.Replace('STONE ID:', '')
								&TefIdAut = &TefIdAut.Replace(':', '')
								&TefIdAut = &TefIdAut.Replace('STONE', '')
								&TefIdAut = &TefIdAut.Replace('ID', '')
								&TefIdAut = &TefIdAut.Trim()

							Case &Mensagem like '%ESTORNO%'
								&IsExtorno = true
						EndCase		
					Endif

					if not &NsuVarchar.IsEmpty() and not &AutorizacaoVarchar.IsEmpty()
						Exit
					Endif

				EndFor	

			Otherwise
				For &Mensagem in &XmlIMprimirLongVarchar.SplitRegEx(';:;')

					&Mensagem = &Mensagem.ToUpper()

					if not &Mensagem.IsEmpty()
						&Count += 1	
						do case
							//Case &Count = 6
							//	&TefBand = &Mensagem
							CAse &Mensagem like '%NSU%'
								&NsuVarchar = RetornaSoNumeros.UDP(&Mensagem)
							Case &Mensagem like '%AUTORIZACAO:%' or &Mensagem like '%AUT:%'
								&AutorizacaoVarchar = RetornaSoNumeros.UDP(&Mensagem)
							Case &Mensagem like '%ID:%' and &TefIdAut.IsEmpty()
								&TefIdAut = &Mensagem
							Case &Mensagem like '%ESTORNO%'
								&IsExtorno = true
						EndCase		
					Endif

					if not &NsuVarchar.IsEmpty() and not &AutorizacaoVarchar.IsEmpty()
						Exit
					Endif

				EndFor	
		EndCase
EndSUb

sub 'GravaItemObs'
	&TefItmID = 0
	For Each Order EmpCod, TefCod, (TefItmID)
		Where EmpCod = &EmPCod
		Where TefCod = &TefCod
		&TefItmID = TefItmID
		Exit
	EndFor
	&TefItmID  += 1

	new
		EmpCod = &EmPCod
		TefCod = &TefCod
		TefItmID = &TefItmID	
		TefMsg = &TefMsg
		TefItmSts = &TEfSts
		TefItmStsSyncServ = 'N'
		TefItmDtaHor = serverNow()
	endnew
	Commit
EndSub
